long long x = 0;
int solve(long long x) {
    int l = 0, r = n - 1;
    while (l <= r)
	{
        int mid = (l + r) / 2;
        if (a[mid] >= -x)
		{
            r = mid - 1;
        }
		else
		{
            l = mid + 1;
        }
    }
    return l;
}
int main()
{
    ios::sync_with_stdio(false);
    cin.tie(0);cout.tie(0);
    cin >> n >> m;
