    // 预处理后缀和
    sum[n] = 0;
    for (int i = n-1; i >= 0; --i)
	{
        sum[i] = sum[i + 1] + a[i];
    }
    while (m--) {
        int op;
        cin >> op;
        if (op == 1)
		{
            int k;
            cin >> k;
            x += k;
        } else if (op == 2)
		{ 
            long long ans = sum[solve(x)] + (n - solve(x)) * x;
